def match_parens(lst):
    # Contar el número de paréntesis abiertos y cerrados en ambas cadenas
    open_count = lst[0].count('(') + lst[1].count('(')
    close_count = lst[0].count(')') + lst[1].count(')')

    # Verificar si es posible obtener una cadena equilibrada
    if open_count == close_count:
        # Verificar si alguna de las concatenaciones es equilibrada
        concat1 = lst[0] + lst[1]
        concat2 = lst[1] + lst[0]

        stack = []
        for char in concat1:
            if char == '(':
                stack.append(char)
            elif char == ')':
                if stack:
                    stack.pop()
                else:
                    break
        else:
            if not stack:
                return 'Yes'

        stack = []
        for char in concat2:
            if char == '(':
                stack.append(char)
            elif char == ')':
                if stack:
                    stack.pop()
                else:
                    break
        else:
            if not stack:
                return 'Yes'

        return 'No'
    else:
        return 'No'
