```python
import heapq

def minPath(grid, k):
    n = len(grid)
    directions = [(1, 0), (-1, 0), (0, 1), (0, -1)]

    min_path = None
    for i in range(n):
        for j in range(n):
            pq = [(grid[i][j], [grid[i][j]])]
            visited = {(i, j): grid[i][j]}

            while pq:
                val, path = heapq.heappop(pq)
                if len(path) == k:
                    if min_path is None or path < min_path:
                        min_path = path
                    break
                for di, dj in directions:
                    ni, nj = i + di, j + dj
                    if 0 <= ni < n and 0 <= nj < n:
                        new_val = grid[ni][nj]
                        new_path = path + [new_val]
                        if (ni, nj) not in visited or new_path < visited[(ni, nj)]:
                            visited[(ni, nj)] = new_path
                            heapq.heappush(pq, (new_val, new_path))
                            i, j = ni, nj
    return min_path
```

